// PROCESSAR DADOS
const items = $input.all();
const rawValues = items.map(i => Object.values(i.json));
const row1 = rawValues[0] || [];
const row2 = rawValues[1] || [];
const romaneios = [];

for (let c = 2; c < row2.length; c += 2) {
  const name = row2[c] || '';
  if (!name || name === 'ESTOQUE INT') continue;
  const dateStr = row1[c] || '';
  let parsedDate = null;
  if (dateStr) {
    const p = String(dateStr).match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
    if (p) parsedDate = new Date(parseInt(p[3]), parseInt(p[2])-1, parseInt(p[1]));
  }
  const itemsRM = {};
  for (let r = 2; r < rawValues.length; r++) {
    const val = rawValues[r][c];
    if (val !== undefined && val !== '' && val !== null) {
      const num = Number(val);
      if (!isNaN(num) && num !== 0) itemsRM[r] = num;
    }
  }
  romaneios.push({ date: parsedDate, name, items: itemsRM });
}

const sorted = [...romaneios.filter(r => r.date).sort((a,b) => a.date - b.date), ...romaneios.filter(r => !r.date)];
const totalRows = rawValues.length;
const totalCols = sorted.length * 2;

function colLetter(n) { let r=''; while(n>0){n--;r=String.fromCharCode(65+n%26)+r;n=Math.floor(n/26);} return r; }

const grid = [];
for (let r = 0; r < totalRows; r++) grid.push(new Array(totalCols).fill(''));

for (let i = 0; i < sorted.length; i++) {
  const rm = sorted[i], t = i*2;
  if (rm.date) grid[0][t] = `${String(rm.date.getDate()).padStart(2,'0')}/${String(rm.date.getMonth()+1).padStart(2,'0')}/${rm.date.getFullYear()}`;
  grid[1][t] = rm.name;
  grid[1][t+1] = 'ESTOQUE INT';
  const prev = t===0 ? 'B' : colLetter(3+t-1), curr = colLetter(3+t);
  for (let r=2; r<totalRows; r++) {
    if (rm.items[r] !== undefined) grid[r][t] = rm.items[r];
    grid[r][t+1] = `=${prev}${r+1}-${curr}${r+1}`;
  }
}

return [{ json: {
  writeRange: 'PROGRAMAÇÃO!C1:'+colLetter(2+totalCols)+totalRows,
  clearRange: 'PROGRAMAÇÃO!C1:DZ'+totalRows,
  values: grid,
  totalRomaneios: sorted.length,
  totalRows
}}];

const input = $('Processar').first().json;
const n = input.totalRomaneios, rows = input.totalRows;
const G={red:0,green:1,blue:0}, LG={red:0.85,green:0.92,blue:0.83}, BL={red:0.56,green:0.67,blue:0.86}, BK={red:0,green:0,blue:0}, RD={red:1,green:0,blue:0};
const sid = 940477380;
const rq = [];
for(let i=0;i<n;i++){
  const c=2+(i*2), hd = input.values[0][i*2] && input.values[0][i*2] !== '';
  rq.push({repeatCell:{range:{sheetId:sid,startRowIndex:0,endRowIndex:1,startColumnIndex:c,endColumnIndex:c+1},cell:{userEnteredFormat:{numberFormat:{type:'DATE',pattern:'dd/mm/yyyy'},backgroundColor:hd?G:LG,textFormat:{bold:true,fontSize:11,foregroundColor:BK},horizontalAlignment:'CENTER',verticalAlignment:'MIDDLE'}},fields:'userEnteredFormat(numberFormat,backgroundColor,textFormat,horizontalAlignment,verticalAlignment)'}});
  rq.push({repeatCell:{range:{sheetId:sid,startRowIndex:0,endRowIndex:1,startColumnIndex:c+1,endColumnIndex:c+2},cell:{userEnteredFormat:{backgroundColor:LG,textFormat:{bold:true,foregroundColor:BK}}},fields:'userEnteredFormat(backgroundColor,textFormat)'}});
  rq.push({repeatCell:{range:{sheetId:sid,startRowIndex:1,endRowIndex:2,startColumnIndex:c,endColumnIndex:c+1},cell:{userEnteredFormat:{backgroundColor:BL,textFormat:{bold:true,fontSize:10,foregroundColor:BK},horizontalAlignment:'CENTER',verticalAlignment:'MIDDLE',wrapStrategy:'WRAP'}},fields:'userEnteredFormat(backgroundColor,textFormat,horizontalAlignment,verticalAlignment,wrapStrategy)'}});
  rq.push({repeatCell:{range:{sheetId:sid,startRowIndex:1,endRowIndex:2,startColumnIndex:c+1,endColumnIndex:c+2},cell:{userEnteredFormat:{backgroundColor:LG,textFormat:{bold:true,fontSize:10,foregroundColor:BK},horizontalAlignment:'CENTER',verticalAlignment:'MIDDLE'}},fields:'userEnteredFormat(backgroundColor,textFormat,horizontalAlignment,verticalAlignment)'}});
  rq.push({repeatCell:{range:{sheetId:sid,startRowIndex:2,endRowIndex:rows,startColumnIndex:c+1,endColumnIndex:c+2},cell:{userEnteredFormat:{backgroundColor:LG,textFormat:{bold:true,foregroundColor:BK}}},fields:'userEnteredFormat(backgroundColor,textFormat)'}});
}
const tc=2+n*2;
rq.push({repeatCell:{range:{sheetId:sid,startRowIndex:2,endRowIndex:rows,startColumnIndex:2,endColumnIndex:tc},cell:{userEnteredFormat:{horizontalAlignment:'CENTER',verticalAlignment:'MIDDLE'}},fields:'userEnteredFormat(horizontalAlignment,verticalAlignment)'}});
rq.push({addConditionalFormatRule:{rule:{ranges:[{sheetId:sid,startRowIndex:2,endRowIndex:rows,startColumnIndex:2,endColumnIndex:tc}],booleanRule:{condition:{type:'NUMBER_LESS',values:[{userEnteredValue:'0'}]},format:{backgroundColor:RD,textFormat:{foregroundColor:BK}}}},index:0}});
return [{json:{requests:rq}}];
